import React, { useState } from 'react';
import axios from 'axios';

const PostProject = () => {
    const [project, setProject] = useState({
        title: '',
        description: '',
        budget: '',
        clientName: ''
    });

    const handleChange = (e) => {
        setProject({ ...project, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            // जेव्हा बॅकएंड रन होईल तेव्हा हा डेटा तिथे जाईल
            const res = await axios.post('http://localhost:8080/api/projects', project);
            alert("Project Posted Successfully!");
            console.log(res.data);
        } catch (err) {
            alert("Backend is not running, but form is working!");
        }
    };

    return (
        <div style={{ padding: '20px', maxWidth: '500px' }}>
            <h2>Post a New Project</h2>
            <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                <input type="text" name="title" placeholder="Project Title" onChange={handleChange} required />
                <textarea name="description" placeholder="Project Description" onChange={handleChange} required />
                <input type="number" name="budget" placeholder="Budget (₹)" onChange={handleChange} required />
                <input type="text" name="clientName" placeholder="Your Name" onChange={handleChange} required />
                <button type="submit" style={{ padding: '10px', background: '#282c34', color: 'white', cursor: 'pointer' }}>
                    Post Project
                </button>
            </form>
        </div>
    );
};

export default PostProject;
